import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            List<String> logs = new ArrayList<>(N);
            for (int i = 0; i < N; i++) {
                logs.add(br.readLine());
            }
            String filterLine = br.readLine().trim();
            String[] fParts = filterLine.split("\\s+");
            String filterLevel = fParts[0];
            String filterKeyword = fParts.length > 1 ? fParts[1] : "";
            boolean any = false;
            for (String log : logs) {
                int colonIdx = log.indexOf(':');
                if (colonIdx == -1) continue;
                String before = log.substring(0, colonIdx).trim();
                String[] parts = before.split("\\s+");
                if (parts.length < 2) continue;
                String level = parts[0];
                String keyword = parts[1];
                boolean match = filterKeyword.isEmpty() ? level.equals(filterLevel)
                        : level.equals(filterLevel) && keyword.equals(filterKeyword);
                if (match) {
                    out.append(log).append('\n');
                    any = true;
                }
            }
            if (!any) out.append("No logs found.").append('\n');
            if (tc != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

